import { useLocation, useNavigate } from "react-router-dom";
import "../App.css";

function QuizResult() {
  const location = useLocation();
  const navigate = useNavigate();

  const result = location.state;

  if (!result) {
    return (
      <div className="page-container">
        <div className="result-box">
          <h2>No result found.</h2>
          <p>Please attempt a quiz first.</p>
          <button className="quiz-button" onClick={() => navigate("/quiz-bank")}>
            Go Back
          </button>
        </div>
      </div>
    );
  }

  // Calculate percentage
  const percentage = Math.round((result.score / result.total) * 100);

  // Determine feedback message and color based on score
  let feedbackMessage = "";
  let barColor = "";

  if (percentage >= 80) {
    feedbackMessage = "Outstanding! Excellent work. 🏆";
    barColor = "#16a34a"; // Green
  } else if (percentage >= 50) {
    feedbackMessage = "Good effort! Keep practicing. 👍";
    barColor = "#ca8a04"; // Yellow
  } else {
    feedbackMessage = "Don't give up! Review the material and try again. 📚";
    barColor = "#dc2626"; // Red
  }

  return (
    <div className="page-container">
      <div className="result-box">
        <h1 style={{ color: "var(--primary-dark)", marginBottom: "8px" }}>Quiz Complete!</h1>
        <h2 style={{ fontWeight: "500", color: "var(--text-soft)" }}>{result.title}</h2>

        {/* Dynamic Feedback Message */}
        <h3 style={{ color: barColor, marginTop: "24px", fontSize: "20px" }}>
          {feedbackMessage}
        </h3>

        {/* Score Breakdown */}
        <p className="result-score" style={{ fontSize: "18px", marginTop: "10px" }}>
          You scored <strong>{result.score}</strong> out of <strong>{result.total}</strong>
        </p>

        {/* Visual Progress Bar */}
        <div className="progress-bar-container">
          <div
            className="progress-bar-fill"
            style={{ 
              width: `${percentage}%`, 
              backgroundColor: barColor 
            }}
          >
            <span className="progress-bar-text">{percentage}%</span>
          </div>
        </div>

        {/* Action Buttons */}
        <div className="result-actions">
          <button className="quiz-button" onClick={() => navigate("/quiz-bank")}>
            Back to Quiz Bank
          </button>

          {/* Optional: If you passed the quiz ID in state from QuizAttempt, you could add a retry button here! */}
        </div>
      </div>
    </div>
  );
}

export default QuizResult;
